function maxPartitionSum(start, k, nums, memo) {
    if (k === 1) {
        return nums.slice(start).reduce((sum, n) => sum + n) / (nums.length - start);
    }
    if (memo[start][k] !== -1) {
        return memo[start][k];
    }
    let sum = 0, ans = 0;
    for (let i = start; i < nums.length - k + 1; ++i) {
        sum += nums[i];
        ans = Math.max(ans, sum / (i - start + 1) + maxPartitionSum(i + 1, k - 1, nums, memo));
    }
    memo[start][k] = ans;
    return ans;
}
